    62→  return MEASUREMENT_PATTERNS.some((pattern) => lowerLine.includes(pattern));
    63→}
    64→
    65→function startsWithNumber(line: string): boolean {
    66→  return /^\s*\d/.test(line);
    67→}
    68→
    69→function isAllCaps(line: string): boolean {
    70→  const letters = line.replace(/[^a-zA-Z]/g, "");
    71→  return letters.length > 0 && letters === letters.toUpperCase();
    72→}
    73→
    74→function looksLikeMetadata(text: string): boolean {
    75→  return METADATA_PATTERNS.some((pattern) => pattern.test(text.trim()));
    76→}
